module RefModule(  
    input wire clk,  
    input wire reset,  
    input wire [15:0] frame_length,  
    output reg valid_frame  
);  

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
    if (reset) begin  
        valid_frame <= 0;  
    end else begin  
        if (frame_length >= 16'd64 && frame_length <= 16'd1518)  
            valid_frame <= 1;  
        else  
            valid_frame <= 0;  
    end  
end  
endmodule
